func ogType(value string) string {
	if strings.TrimSpace(value) == "" {
		return "website"
	}
	return value
}

func termLabels(items []publicrender.TermView) string {
	labels := make([]string, 0, len(items))
	for _, item := range items {
		label := item.Label
		if item.Taxonomy != "" {
			label = item.Taxonomy + ": " + label
		}
		labels = append(labels, label)
	}
	return strings.Join(labels, " | ")
}

func menuIndent(depth int) string {
	if depth <= 0 {
		return "gap-2"
	}
	if depth == 1 {
		return "gap-2 pl-4"
	}
	return "gap-2 pl-8"
}

func menuVariant(active bool) string {
	if active {
		return "default"
	}
	return "link"
}

